INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Day-of-broadcast simulcasts$q$, $q$New episodes of ongoing anime seasons are typically available within an hour of their original Japanese television broadcast.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Large licensed anime catalog$q$, $q$Thousands of subtitled and dubbed series and films spanning decades, from classic titles to current-season releases.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Crunchyroll Manga$q$, $q$Included with the Ultimate Fan plan, giving access to hundreds of digital manga titles alongside the video catalog.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Offline downloads$q$, $q$Episodes can be downloaded for offline viewing, with resolution and device limits that scale by subscription tier.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Multi-device streaming$q$, $q$Higher tiers allow up to four or six simultaneous streams on different devices under one account.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Crunchyroll Game Vault$q$, $q$A curated library of mobile and casual games included with Mega Fan and Ultimate Fan subscriptions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Ad-free viewing$q$, $q$All three paid tiers remove advertising from the video player, unlike the limited free tier.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Broad device support$q$, $q$Native apps for smart TVs, game consoles, mobile devices, and web browsers.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$One of the largest legally licensed anime catalogs available in Western markets$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Simulcasts new episodes close to their original Japanese air date$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c6f2e18b-eae3-454e-9469-bc5dd87574f4', $q$Top-tier plan bundles manga and games alongside video for one price$q$, 2);
