-- Enrichment marathon batch: Crunchyroll, Crypteron, Crystallize, Cscope, CudaText, Cura (Ultimaker Cura), CurlHub, Currencyapi

-- ── Crunchyroll ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Crunchyroll is a subscription video streaming service that specializes in anime, manga, and related Japanese entertainment, offering simulcasts of new episodes alongside a large back catalog of licensed titles. It is owned and operated by Sony through Crunchyroll, LLC, following the 2021 consolidation of Crunchyroll, Funimation, Wakanim, and VRV into a single brand. The platform combines video streaming, a manga reading library, and a curated games catalog under tiered subscription plans.$q$, short_description),
  pricing_model = COALESCE($q$Freemium tiered subscription: an ad-supported free tier plus three paid monthly or annual plans$q$, pricing_model),
  starting_price = COALESCE($q$9.99 USD per month for the Fan plan, or 66.99 USD per year on the discounted Fan Annual plan$q$, starting_price),
  founded_year = COALESCE(2006, founded_year),
  company_size = COALESCE($q$approximately 2,000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Japanese$q$, $q$Spanish$q$, $q$Portuguese$q$, $q$French$q$, $q$German$q$, $q$Italian$q$, $q$Arabic$q$, $q$Russian$q$]::text[],
  seo_title = COALESCE($q$Crunchyroll Review 2026: Pricing, Plans and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Crunchyroll costs in 2026, how its Fan, Mega Fan and Ultimate Fan plans differ, and whether the anime streaming service is worth it.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Crunchyroll is the largest legal anime streaming service outside Japan, founded in 2006 in San Francisco by UC Berkeley computer science graduates Kun Gao, James Lin, Vu Nguyen, and Brandon Ooi. It began as a video-sharing site for fan-subtitled anime before pivoting into a licensed streaming platform that simulcasts new episodes within hours of their Japanese broadcast. Sony Pictures Television acquired a controlling stake in the anime distributor Funimation in 2017 and later purchased Crunchyroll itself from AT and T and WarnerMedia in 2020 for 1.175 billion dollars, completing the deal in 2021. In March 2022, Sony merged Crunchyroll, Funimation, Wakanim, and the VRV service into a single unified brand operated as Crunchyroll, LLC, headquartered in San Francisco with additional major offices in Coppell, Texas (the former Funimation headquarters) and Culver City, California. As of 2026 the company reports roughly 21 million paid subscriptions and around 2,000 employees worldwide. The service is priced on three paid tiers in the United States: Fan at 9.99 dollars per month with ad-free viewing and single-device offline downloads; Mega Fan at 13.99 dollars per month adding four simultaneous streams, HD offline downloads, and access to the Crunchyroll Game Vault; and Ultimate Fan at 17.99 dollars per month adding six simultaneous streams and full access to Crunchyroll Manga. A discounted Fan Annual plan is available for 66.99 dollars per year. These prices reflect a 2026 increase from the prior 7.99 and 11.99 dollar tiers. Crunchyroll's core catalog spans thousands of anime series and films across genres such as shonen, isekai, slice of life, and sports, plus a growing slate of Crunchyroll-branded original productions and co-productions with Japanese studios. The platform supports apps on smart TVs, game consoles, mobile devices, and web browsers, with offline downloads, multi-device profiles, and parental controls. Competitively, Crunchyroll differentiates itself from general-purpose streamers like Netflix, Max, and Disney Plus by focusing entirely on anime and by simulcasting new episodes on the same day they air in Japan, which is a major draw for fans who want to avoid spoilers. It also differentiates itself from anime-adjacent services by bundling a manga reading library and a games catalog into its top subscription tier, something none of its direct competitors, such as HIDIVE, currently replicate at the same scale. Common criticisms include recurring price increases since 2023, advertising on the free ad-supported tier, occasional licensing splits where certain high-profile titles stream exclusively on rival platforms like Netflix or Max, and simultaneous-stream limits that require upgrading to unlock multi-device household use. For buyers researching Crunchyroll in 2026, the key facts are: it is Sony-owned, headquartered in San Francisco, founded in 2006, priced from 9.99 dollars per month, and built around simulcast anime, manga, and games in a single subscription.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c6f2e18b-eae3-454e-9469-bc5dd87574f4';

