-- ── Cscope ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cscope is a free, open-source, terminal-based tool for browsing and navigating large C source code bases, letting developers quickly find function definitions, callers, symbol usages, and text patterns across a codebase. It originated at Bell Labs in the early 1980s, was contributed to open source under a BSD license in 2000, and remains in active use today, notably as a supported navigation target in the Linux kernel build system.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source under the BSD license$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(1982, founded_year),
  company_size = COALESCE($q$Not applicable, a volunteer-maintained open-source project rather than a company$q$, company_size),
  headquarters = COALESCE($q$Originally developed at Bell Labs in Murray Hill, New Jersey, United States; now maintained as a distributed open-source project without a fixed headquarters$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Cscope: Free C Source Code Browser and Navigation Tool$q$, seo_title),
  seo_meta_description = COALESCE($q$Cscope is a free, open-source terminal tool for navigating large C codebases. Learn its history, features, and how it compares to modern IDEs.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cscope is a text-based source code browsing and navigation tool created by Joe Steffen in the early 1980s while working at Bell Labs, originally to help him navigate his own C programming work on a PDP-11 system. It grew in popularity internally at AT and T and Bell Labs as colleagues requested additional features, and it was eventually distributed across every AT and T location worldwide through the company's internal exptools network for experimental tools, becoming a dependency for many large internal projects with codebases reaching into the millions of lines. The tool later became part of the official AT and T Unix distribution, passing through several corporate owners as the Unix business changed hands, from Unix System Laboratories to Novell and then to The Santa Cruz Operation (SCO). In April 2000, SCO announced it was contributing cscope to the open-source community under a BSD license, and SCO engineer Petr Sorfa became its first open-source maintainer, notably porting the codebase to build with the GNU gcc toolchain. Maintenance responsibilities later passed to Hans-Bernhard Broker and Neil Horman, and the project has continued to be maintained on SourceForge and, more recently, in community forks on GitHub, with the last widely referenced stable release being version 15.9 from July 2018. Functionally, cscope builds a searchable database from a codebase and then lets developers run fast lookups for where a function or symbol is defined, where it is called, where a text string or regular expression appears, and where a particular file includes another file, all from a lightweight terminal interface. It integrates tightly with classic Unix editors, most notably vim and Emacs, letting developers jump directly from a search result to the corresponding line in their editor. While its native support targets C source code, it can also process C++, Java, lex, and yacc files, though with some limitations compared to full multi-language IDEs. Because of its speed and low resource footprint, cscope remains a preferred navigation tool for developers working on very large, low-level C codebases, most famously the Linux kernel, which ships a dedicated make target specifically for building a cscope database of the kernel source tree. It is also cited as valuable for security auditing and reverse engineering work, where quickly tracing how a function or variable is used across an unfamiliar, sprawling codebase is essential. Compared to modern IDE-based navigation in tools like Visual Studio Code, CLion, or language-server-based editors, cscope's terminal interface is dated and it lacks built-in refactoring or semantic type-aware navigation, and its index must be manually rebuilt to stay accurate after code changes. However, its minimal dependencies, fast performance even on huge codebases, and ability to work seamlessly over SSH on remote or embedded development machines keep it in active use among systems programmers, kernel developers, and security researchers who work primarily in terminal environments. As free, open-source software with no company behind it, cscope has no pricing tiers, subscription plans, or commercial support offering; support comes from community maintainers and long-standing documentation rather than a vendor.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e78368c5-1241-4e12-88e3-2ea4cbc61826';

