-- ── CudaText ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$CudaText is a free, open-source, cross-platform text and code editor written in Object Pascal using the Lazarus IDE, created by developer Alexey Torgashin as a successor to his earlier SynWrite editor. First released around 2015, it emphasizes fast startup, low resource usage, and extensibility through a Python plugin system, with native builds available for Windows, Linux, macOS, and FreeBSD.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source under the Mozilla Public License 2.0, usable for personal and commercial purposes at no cost$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2015, founded_year),
  company_size = COALESCE($q$Not applicable, an independently developed open-source project rather than a company$q$, company_size),
  headquarters = COALESCE($q$Not applicable, open-source project with its lead developer based in Russia$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Russian$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Chinese$q$, $q$Portuguese$q$]::text[],
  seo_title = COALESCE($q$CudaText: Free Open-Source Code Editor Review$q$, seo_title),
  seo_meta_description = COALESCE($q$CudaText is a free, open-source cross-platform code editor with Python plugins and 300+ syntax lexers. See its features, pros, cons, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$CudaText is a free, open-source, cross-platform text and source code editor created by developer Alexey Torgashin, first released around 2015 as the successor to his earlier Windows editor SynWrite after that project's development was discontinued. The application's core is written in Object Pascal using the Lazarus IDE, which gives it a small footprint, fast startup time (roughly 0.3 seconds with around 30 plugins loaded, according to the project's own benchmarks), and native builds for Windows, Linux, macOS, and FreeBSD without relying on a heavier cross-platform framework like Electron. CudaText is licensed under the Mozilla Public License 2.0, making it free to use for both personal and commercial purposes, and its source code is publicly maintained on GitHub under the Alexey-T/CudaText repository, with an active release history of incremental version updates. The editor ships with an extensive built-in feature set aimed at developers and technical writers: syntax highlighting through more than 300 bundled lexers covering a very wide range of programming and markup languages, a code tree panel that shows the structure of functions, classes, and other symbols for languages whose lexer supports it, code folding, multiple carets and multiple selections for simultaneous multi-point editing, find and replace with regular expression support, and the ability to split the editing window into two, three, four, or six groups of tabs for working across several files at once. It includes a command palette with fuzzy matching for quickly executing commands by name, a minimap and micromap for visual navigation of large files, and a binary and hex viewer capable of handling files of effectively unlimited size, including multi-gigabyte log files that would overwhelm many conventional text editors. The single biggest differentiator for CudaText is its extensibility: it supports add-ons written in Python, covering plugins, linters, custom code tree parsers for additional languages, and external tool integrations, and it ships with several preinstalled plugins such as a Project Manager for organizing multi-file projects and a Snippets system that supports the same snippet format used by Visual Studio Code. Because CudaText has no company or commercial entity behind it, it has no pricing tiers, subscription plans, or paid support offering; all funding and development effort comes from its lead maintainer and open-source community, with support delivered through GitHub issues, the Free Pascal community wiki, and user forums rather than a formal customer support channel. Compared to modern mainstream editors such as Visual Studio Code or Sublime Text, CudaText's plugin ecosystem is considerably smaller and it lacks the deep language server protocol and IntelliSense-style integrations that dominate contemporary coding workflows, and its interface design reads as more utilitarian than polished. However, its low resource requirements, fast startup even with many plugins loaded, native support for less common platforms like FreeBSD, and genuinely free-for-commercial-use licensing make it a practical choice for developers on older or resource-constrained hardware, for portable USB-based development setups, and for anyone who wants a lightweight, script-extensible editor without subscription costs.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '3c8e9c26-c142-40c1-852c-62506bc54e8c';

