-- ── Cura (Ultimaker Cura) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Cura, commonly known as Ultimaker Cura or UltiMaker Cura, is a free, open-source 3D printing slicer that converts 3D model files into printer-ready instructions. Originally created by David Braam and later adopted and maintained by Ultimaker, it is now developed by UltiMaker following the 2022 merger of Ultimaker and MakerBot. The software offers more than 400 configurable print settings and is reported to serve over one million users worldwide.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source desktop application under the LGPLv3 license; UltiMaker Cura Enterprise is available separately for businesses via custom quote$q$, pricing_model),
  starting_price = COALESCE($q$Free for the standard desktop application; custom pricing for UltiMaker Cura Enterprise$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Approximately 400 employees at UltiMaker, the company that maintains Cura$q$, company_size),
  headquarters = COALESCE($q$Utrecht, Netherlands (UltiMaker headquarters)$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$Dutch$q$, $q$German$q$, $q$French$q$, $q$Spanish$q$, $q$Italian$q$, $q$Portuguese$q$, $q$Russian$q$, $q$Japanese$q$, $q$Korean$q$, $q$Chinese$q$]::text[],
  seo_title = COALESCE($q$Ultimaker Cura Review 2026: Features, Pricing and Guide$q$, seo_title),
  seo_meta_description = COALESCE($q$Ultimaker Cura is a free open-source 3D printing slicer with 400-plus settings. See its features, licensing, pros, cons, and Enterprise pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Cura, now branded UltiMaker Cura, is a free and open-source 3D printing slicer application that converts digital 3D model files into the layer-by-layer machine instructions, known as G-code, that fused filament fabrication 3D printers use to build physical objects. The software was originally created by David Braam, who was later hired by the Dutch 3D printer manufacturer Ultimaker to continue developing and maintaining it as the company's flagship slicing software. Ultimaker itself was founded in 2011 in the Netherlands by Martijn Elserman, Erik de Bruijn, and Siert Wijnia, and the company's headquarters later moved to Utrecht. In September 2022, Ultimaker completed a merger with rival 3D printer maker MakerBot, forming a combined company branded UltiMaker, backed by investors NPM Capital and Stratasys; the merged company continues to develop and maintain Cura as its primary slicing product alongside MakerBot's existing hardware lines such as the METHOD and SKETCH printers. UltiMaker now employs roughly 400 people and is headquartered in Utrecht, Netherlands. Cura's licensing has changed over its history: it originally launched under the GNU Affero General Public License version 3, then switched to the more permissive LGPLv3 license on September 28, 2017, specifically to allow easier integration with third-party CAD applications. The software is reported to be used by more than one million people globally, processing roughly 1.4 million print jobs every week, and it was named Software Tool of the Year at the 2019 3D Printing Industry Awards in London. Functionally, Cura offers more than 400 individually configurable print settings covering layer height, infill density and pattern, print speed, support structures including advanced tree supports, adaptive layers, and multi-material or multi-extruder printing, giving both beginners using simplified presets and advanced users fine-grained control the same underlying engine. It supports importing standard 3D model formats including STL, OBJ, X3D, and 3MF, ships with an extensive built-in library of printer profiles covering hundreds of desktop 3D printers beyond just UltiMaker and MakerBot hardware, and includes a layer-by-layer print preview for inspecting the sliced result before printing. A plugin marketplace lets users add community-built extensions, and Cura Connect and the UltiMaker Digital Factory cloud service extend the software with remote print monitoring and print queue management for multiple networked printers, primarily aimed at UltiMaker's own hardware. For organizations that need more stability and governance than the standard rolling-release desktop app, UltiMaker offers Cura Enterprise, a business-oriented edition that receives only two thoroughly tested updates per year, supports each release for 12 months including security patches, and can be centrally deployed and configured across an organization using standard software distribution systems; pricing for Cura Enterprise is not publicly listed and requires contacting UltiMaker directly. The free standard version of Cura remains cross-platform, running natively on Windows, macOS, and Linux, and is generally considered one of the most widely adopted slicers in the desktop 3D printing community, competing with alternatives such as PrusaSlicer, Simplify3D, and Bambu Studio.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '8b7bbdb7-187c-4a21-ab16-a809bd731985';

