-- ── Currencyapi ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Currencyapi.com is a developer-focused REST API that delivers real-time and historical foreign exchange rates across more than 170 currencies and cryptocurrencies. Founded in 2019 by Oli Girling and operated by the UK-registered House of Apis Ltd, it offers a free tier plus four paid subscription tiers priced by monthly request volume and update frequency. The service reports handling more than 50 million requests per month for over 10,000 clients.$q$, short_description),
  pricing_model = COALESCE($q$Tiered monthly subscription with a free tier and four paid tiers priced by request volume, plus a custom enterprise plan$q$, pricing_model),
  starting_price = COALESCE($q$Free for 300 requests per month; paid plans start at 9.99 USD per month$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Small team, operated by House of Apis Ltd, a UK-registered company$q$, company_size),
  headquarters = COALESCE($q$London, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Currencyapi.com Review 2026: Pricing and Features$q$, seo_title),
  seo_meta_description = COALESCE($q$Currencyapi.com is a currency exchange rate API for developers. See its pricing tiers, update frequency, supported currencies, and use cases.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Currencyapi.com is a REST API service that provides real-time and historical foreign exchange rate data, along with conversion and range endpoints, to developers building fintech, ecommerce, accounting, and travel applications. The service was started in 2019 by Oli Girling, a software engineer based in London who originally built the tool to solve a currency data problem in his own projects before opening it up as a public API that has since grown into a service trusted by more than 10,000 clients handling over 50 million requests per month. It is operated by House of Apis Ltd, a company registered in the United Kingdom, and the business is headquartered in London. The API covers more than 170 world currencies and cryptocurrencies, and it reports 99.99 percent uptime over trailing 12-month periods, with rate data aggregated from multiple financial data providers and international banks rather than a single source. Pricing follows a five-tier structure. The Free plan costs nothing and includes 300 requests per month with a 10 request-per-minute rate limit, daily rate updates, and a single API key, making it suitable only for early testing rather than production use. The Small plan costs 9.99 USD per month and raises the allowance to 15,000 requests per month with an unlimited per-minute rate limit, hourly rate updates, commercial use rights, one API key, an audit trail, rate conversion, and email support. The Medium plan, marketed as the most popular tier, costs 39.99 USD per month for 600,000 requests per month, two API keys including a sandbox key, 60-second update frequency, a historical range endpoint, and team management features. The Large plan costs 79.99 USD per month for 1,700,000 requests per month, five API keys, IP and URL whitelisting, a service level agreement, and included usage overages. Above that, a Custom plan offers negotiable pricing with tailored request volumes, custom API keys, dedicated support, and a custom SLA for very high-volume users who exceed the Large plan's limits. Across all paid tiers, the service includes HTTPS encryption, commercial usage rights, and both latest and historical exchange rate data, with the update frequency tightening from daily on the free tier down to 60 seconds on the Medium and Large tiers, which is a meaningful differentiator for time-sensitive use cases like point-of-sale currency conversion or high-frequency financial applications. Compared to other currency data providers such as Open Exchange Rates, Fixer, or the European Central Bank's free public feed, currencyapi.com positions itself around an accessible low starting price point of under 10 dollars per month for commercial use, a relatively simple REST JSON interface, and inclusion of both fiat currencies and cryptocurrencies in the same feed. Its main limitations relative to larger competitors are a smaller published SDK ecosystem, less publicly documented historical data depth, and the fact that very high-volume or highly customized needs require a manually negotiated custom plan rather than a fully self-serve higher tier. For a typical small to mid-sized application needing reliable, reasonably fresh exchange rate data without an enterprise contract, currencyapi.com's Small or Medium tier is the most commonly referenced entry point given its price-to-request-volume ratio.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'ff2032a2-7c89-47ac-91e1-17954079869e';

